#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

const CAPACITY = 5;
const REFILL_MS_PER_TOKEN = 200; // 1 token per 200ms => 5 tokens/sec.

type Bucket = { tokens: number; updatedAt: number };

const buckets = new Map<string, Bucket>();

function refill(clientId: string, now: number): Bucket {
  let bucket = buckets.get(clientId);
  if (!bucket) {
    bucket = { tokens: CAPACITY, updatedAt: now };
    buckets.set(clientId, bucket);
    return bucket;
  }
  const elapsed = now - bucket.updatedAt;
  if (elapsed > 0) {
    const refilled = elapsed / REFILL_MS_PER_TOKEN;
    // Continuous, time-based refill capped hard at CAPACITY.
    bucket.tokens = Math.min(CAPACITY, bucket.tokens + refilled);
    bucket.updatedAt = now;
  }
  return bucket;
}

Bun.serve({
  port,
  fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/resource") {
      const clientId = request.headers.get("x-client-id");
      if (!clientId) {
        return Response.json({ error: "missing_client_id" }, { status: 400 });
      }

      const now = Date.now();
      const bucket = refill(clientId, now);

      if (bucket.tokens >= 1) {
        bucket.tokens -= 1;
        const remaining = Math.floor(bucket.tokens);
        return Response.json(
          { ok: true },
          {
            status: 200,
            headers: { "X-RateLimit-Remaining": String(remaining) },
          },
        );
      }

      // Seconds until at least one full token is available.
      const msUntilToken = (1 - bucket.tokens) * REFILL_MS_PER_TOKEN;
      const retryAfter = Math.max(1, Math.ceil(msUntilToken / 1000));
      return Response.json(
        { error: "rate_limited" },
        {
          status: 429,
          headers: {
            "Retry-After": String(retryAfter),
            "X-RateLimit-Remaining": "0",
          },
        },
      );
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`token-bucket reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
